public fun validate(validation: SingletonRaise<None>.(A) -> Unit): Option<A> = when (this) {
  is None -> this
  is Some -> arrow.core.raise.fold({ validation(SingletonRaise(this), value) }, { None }, { this })
}

public inline fun <reified B> Option<*>.filterIsInstance(): Option<B> =
  flatMap {
    when (it) {
      is B -> Some(it)
      else -> None
    }
  }

public inline fun <Error, A> either(block: Raise<Error>.() -> A): Either<Error, A> {
  contract { callsInPlace(block, InvocationKind.AT_MOST_ONCE) }
  return fold(block, { Either.Left(it) }, { Either.Right(it) })
}

data class OfTypeMatcher<in T : Any>(
    val cls: KClass<*>,
) : Matcher<T> {
    override fun match(arg: T?): Boolean = cls.isInstance(arg)

    override fun toString() = "ofType(${cls.simpleName})"
}

open fun <T> elementAt(i: Int, clazz: KClass<*>): T =
        if (i < _values.size) {
            _values[i] as T
        } else {
            throw NoParameterFoundException(
                "Can't get injected parameter #$i from $this for type '${clazz.getFullName()}'",
            )
        }

private fun buildIndices(): Map<String, Int> {
    val indices = HashMap<String, Int>()
    for (i in names.indices) {
        indices[names[i]] = i
    }
    return indices
}

if (bytesArray == null) {
    bytesArray = FileInputStream(imageUrl).use { fileInputStream ->
        fileInputStream.readBytes()
    }

    cachedBytes = bytesArray
}

while (remaining > 0 && !isClosedForRead) {
    if (readBuffer.exhausted()) awaitContent()

    val size = minOf(remaining.toLong(), readBuffer.remaining)
    readBuffer.readTo(result, size)
    remaining -= size.toInt()
}

@OptIn(ExperimentalTypeInference::class)
public inline fun <E, EE, A> Either<E, A>.recover(recover: Raise<EE>.(E) -> A): Either<EE, A> {
  contract {
    callsInPlace(recover, InvocationKind.AT_MOST_ONCE)
    (this@recover is Left) holdsIn recover
  }
  return handleErrorWith { either { recover(it) } }
}

@RaiseDSL @Suppress("CONTRACT_NOT_ALLOWED")
  public fun <A> Either<Error, A>.bind(): A {
    contract { returns() implies (this@bind is Either.Right) }
    when (this) {
      is Either.Left -> raise(value)
      is Either.Right -> return value
    }
  }

fun identity(table: Table): String = (table as? Alias<*>)
        ?.let { "${identity(it.delegate)} ${db.identifierManager.quoteIfNecessary(it.alias)}" }
        ?: db.identifierManager.quoteIfNecessary(
            @OptIn(InternalApi::class)
            table.tableName.inProperCase()
        )

for ((type, _) in typesWithTargetName.filterValues { it == null }) {
  val name = uniqueName(type.name, usedNames.keys.toSet())
  usedNames[name.lowercase()] = type
}

if (fieldSpecs.isEmpty()) {
  add("return true;\n")
} else {
  addStatement("\$T that = (\$T) o", typeJavaClass, typeJavaClass)
  add("return $L;\n", if (fieldSpecs.isEmpty()) "true" else fieldSpecs.equalsCode())
}

when (nullableFieldStyle) {
  JavaNullable.JAVA_OPTIONAL -> CodeBlock.of("$T.empty()", JavaClassNames.JavaOptional)
  JavaNullable.GUAVA_OPTIONAL -> CodeBlock.of("$T.absent()", JavaClassNames.GuavaOptional)
  else -> CodeBlock.of("$T.absent()", JavaClassNames.Optional)
}

when (nullableFieldStyle) {
  JavaNullable.JETBRAINS_ANNOTATIONS -> JavaClassNames.JetBrainsNullable
  JavaNullable.ANDROID_ANNOTATIONS -> JavaClassNames.AndroidNullable
  JavaNullable.JSR_305_ANNOTATIONS -> JavaClassNames.Jsr305Nullable
  else -> null
}

when (nullableFieldStyle) {
  JavaNullable.JETBRAINS_ANNOTATIONS -> JavaClassNames.JetBrainsNonNull
  JavaNullable.ANDROID_ANNOTATIONS -> JavaClassNames.AndroidNonNull
  JavaNullable.JSR_305_ANNOTATIONS -> JavaClassNames.Jsr305NonNull
  else -> null
}

when (type) {
  is IrListType -> resolveIrType(type.ofType).filterTypeUseAnnotations().wrapInList()
  is IrModelType -> resolveAndAssert(ResolverKeyKind.Model, type.path)
  is IrScalarType -> resolveIrScalarTargetOrPrimitive(type, asPrimitiveType = generatePrimitiveTypes)
  is IrNamedType -> resolveAndAssert(ResolverKeyKind.SchemaType, type.name)
}

when {
  useTypenameFromArgument && property.info.responseName == "__typename" -> CodeBlock.of(typename)
  property.info.type.optional -> CodeBlock.of("%T", KotlinSymbols.Absent)
  else -> CodeBlock.of("null")
}

if (reader.peek() == JsonReader.Token.NULL) {
  reader.skipValue()
  Optional.Absent
} else {
  Optional.Present(wrappedAdapter.fromJson(reader, customScalarAdapters))
}

if (reader.peek() == JsonReader.Token.NULL) {
  val error = customScalarAdapters.firstErrorStartingWith(reader.getPath())
  if (error != null) {
    reader.skipValue()
    throw ApolloGraphQLException(error)
  }
}

if (items.isEmpty()) {
    error("Resource with ID='$id' not found")
} else {
    error("Resource with ID='$id' has more than one file: ${items.joinToString { it.path }}")
}

when (recordType) {
    "plurals" -> recordData.decodeAsPlural()
    "string-array" -> recordData.decodeAsArray()
    else -> recordData.decodeAsString()
}

if ((remaining >= 2 || awaitContent(min = 2)) && buffer[1] == LF) {
    discard(2)
    return true
}

if (charset === Charsets.UTF_8) {
    val string = text.concatToString(fromIndex, fromIndex + toIndex)
    return writeString(string, 0, toIndex - fromIndex)
}
